import{_ as t,o as a,c as l,a0 as n}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"The Default Events","description":"","frontmatter":{},"headers":[],"relativePath":"events/default-events.md","filePath":"events/default-events.md"}'),i={name:"events/default-events.md"};function o(r,e,s,d,h,c){return a(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="the-default-events" tabindex="-1">The Default Events <a class="header-anchor" href="#the-default-events" aria-label="Permalink to &quot;The Default Events&quot;">​</a></h1><p>Kingshot Event Tracker starts with seven built-in event templates. These are meant to save setup time and give you sensible starting rules for the most common Kingshot events.</p><blockquote><p>Screenshot placeholder: event-bear-trap.png</p></blockquote><p>Every default template follows one important rule:</p><ul><li>it can be edited</li><li>it can be customized into a scoped copy</li><li>it cannot be deleted</li></ul><p>That protection is part of the platform safety rules. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="the-seven-default-templates" tabindex="-1">The seven default templates <a class="header-anchor" href="#the-seven-default-templates" aria-label="Permalink to &quot;The seven default templates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Event</th><th>Main style</th><th>Notes</th></tr></thead><tbody><tr><td><a href="./bear-trap.html">Bear Trap</a></td><td>single-session score event</td><td>Damage-based alliance rally</td></tr><tr><td><a href="./viking-vengeance.html">Viking Vengeance</a></td><td>single-session score event</td><td>Points-based alliance defense</td></tr><tr><td><a href="./alliance-mobilization.html">Alliance Mobilization</a></td><td>multi-day cumulative event</td><td>Daily totals build toward one running score</td></tr><tr><td><a href="./alliance-brawl.html">Alliance Brawl</a></td><td>multi-stage event</td><td>Stage choice on import matters</td></tr><tr><td><a href="./kingdom-of-power.html">Kingdom of Power</a></td><td>kingdom-wide multi-stage event</td><td>Usually tracked with kingdom results and KvK prep</td></tr><tr><td><a href="./strongest-governor.html">Strongest Governor</a></td><td>multi-stage individual event</td><td>Daily stage or total standings</td></tr><tr><td><a href="./sanctuary-battle.html">Sanctuary Battle</a></td><td>participation and control event</td><td>Not a normal score event</td></tr></tbody></table><h2 id="what-all-seven-have-in-common" tabindex="-1">What all seven have in common <a class="header-anchor" href="#what-all-seven-have-in-common" aria-label="Permalink to &quot;What all seven have in common&quot;">​</a></h2><p>All default events already come with:</p><ul><li>a category and visual style</li><li>import aliases to help screenshot matching</li><li>reward tracking turned on</li><li>participation tracking turned on</li></ul><p>Most of them are ordinary score events. Sanctuary Battle is the exception and should be treated differently.</p><h2 id="why-editing-is-allowed" tabindex="-1">Why editing is allowed <a class="header-anchor" href="#why-editing-is-allowed" aria-label="Permalink to &quot;Why editing is allowed&quot;">​</a></h2><p>The default templates are not meant to lock you into one exact setup forever. You can adjust them to fit how your kingdom or alliance wants to track:</p><ul><li>score labels</li><li>stage labels</li><li>import rules</li><li>participant policies</li><li>analytics visibility</li></ul><p>If you need a variant that only your kingdom or alliance should use, create a custom copy instead of forcing everyone onto one shared version.</p><h2 id="before-you-change-one" tabindex="-1">Before you change one <a class="header-anchor" href="#before-you-change-one" aria-label="Permalink to &quot;Before you change one&quot;">​</a></h2><p>Read the event-specific page first so you understand how that default is meant to behave:</p><ul><li><a href="./bear-trap.html">Bear Trap</a></li><li><a href="./viking-vengeance.html">Viking Vengeance</a></li><li><a href="./alliance-mobilization.html">Alliance Mobilization</a></li><li><a href="./alliance-brawl.html">Alliance Brawl</a></li><li><a href="./kingdom-of-power.html">Kingdom of Power</a></li><li><a href="./strongest-governor.html">Strongest Governor</a></li><li><a href="./sanctuary-battle.html">Sanctuary Battle</a></li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./templates-overview.html">Event Templates &amp; Instances Explained</a></li><li><a href="./../how-to/create-custom-event.html">Create a Custom Event</a></li><li><a href="./../how-to/edit-event-template.html">Edit an Event Template</a></li><li><a href="./../how-to/event-settings.html">Configure Event Settings</a></li></ul>',21)])])}const p=t(i,[["render",o]]);export{m as __pageData,p as default};
